export const meta = { name: 'parallel_prime_check', description: 'Run two independent primality checks with failure tolerance, then synthesize surviving evidence.', phases: [{ title: 'Independent checks' }, { title: 'Synthesis' }] };

phase('Independent checks');
const checks = [
  { name: 'trial_division', prompt: 'Independently determine whether 17 is prime using trial division through sqrt(17). Return one compact sentence stating the evidence. Do not use JSON.' },
  { name: 'factor_argument', prompt: 'Independently determine whether 17 is prime by checking possible prime divisors. Return one compact sentence stating the evidence. Do not use JSON.' }
];

const results = await parallel(checks.map(check => async () => {
  try {
    const evidence = await agent(check.prompt);
    return { name: check.name, ok: true, evidence };
  } catch (error) {
    return { name: check.name, ok: false, error: String(error && error.message ? error.message : error) };
  }
}));

const surviving = results.filter(result => result.ok).map(result => ({ checker: result.name, evidence: result.evidence }));
const failedChecks = results.filter(result => !result.ok).length;
if (surviving.length === 0) throw new Error('All primality checks failed');

phase('Synthesis');
const synthesis = await agent(`Synthesize the surviving independent evidence below. Return ONLY valid compact JSON with exactly these keys: "prime" (boolean), "evidence" (a concise string), and "failedChecks" (integer). The number failedChecks must be ${failedChecks}. Evidence: ${JSON.stringify(surviving)}`);
const text = typeof synthesis === 'string' ? synthesis : String(synthesis);
const cleaned = text.trim().replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '');
const parsed = JSON.parse(cleaned);
return { prime: Boolean(parsed.prime), evidence: String(parsed.evidence), failedChecks };

